mapper.insert:
INSERT INTO recipes (
	user_id, title, title_image, description, cooking_time,
	difficulty_id, purpose_id, cuisine_id, is_ai_generated, is_public
) VALUES (
			 #{userId}, #{title}, #{titleImage}, #{description}, #{cookingTime},
			 #{difficultyId}, #{purposeId}, #{cuisineId}, #{isAiGenerated}, #{isPublic}
		 )

INSERT INTO recipe_ingredients (
	recipe_id, name, normalized_name, quantity, unit, is_ai_generated
) VALUES (
			 #{recipeId}, #{name}, #{normalizedName}, #{quantity}, #{unit}, #{isAiGenerated}
		 )

INSERT INTO recipe_steps (
	recipe_id, step_order, content
) VALUES (
			 #{recipeId}, #{stepOrder}, #{content}
		 )

INSERT INTO recipe_nutrients (
	recipe_id, nutrient_name, amount, unit
) VALUES (
			 #{recipeId}, #{nutrientName}, #{amount}, #{unit}
		 )

mapper.update:
UPDATE recipes
SET is_public = #{isPublic}
WHERE id = #{id}

mapper.select:
SELECT id
FROM recipe_likes
WHERE user_id = #{userId}
  AND recipe_id = #{recipeId}

SELECT EXISTS (
	SELECT 1
	FROM recipe_view_log
	WHERE user_id = #{userId}
	  AND recipe_id = #{recipeId}
)
